import React, { useState, useEffect } from "react";
import Lightbox from "yet-another-react-lightbox";
import "yet-another-react-lightbox/styles.css";
import Thumbnails from "yet-another-react-lightbox/plugins/thumbnails";
import Zoom from "yet-another-react-lightbox/plugins/zoom";
import AOS from "aos";
import "aos/dist/aos.css";

function Gallery() {
  const [open, setOpen] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    AOS.init({ duration: 1000, once: true });
    // Simulate a short loader for smoother UX
    const timer = setTimeout(() => setLoading(false), 1000);
    return () => clearTimeout(timer);
  }, []);

  const slides = [
    { src: process.env.PUBLIC_URL + "/images/optimized/IMG_0422.webp", title: "Engagement photo" },
    { src: process.env.PUBLIC_URL + "/images/optimized/DSC07516.webp", title: "Engagement photo" },
    { src: process.env.PUBLIC_URL + "/images/optimized/DSC07488.webp", title: "Engagement photo" },
    { src: process.env.PUBLIC_URL + "/images/optimized/DSC07510.webp", title: "Engagement photo" },
    { src: process.env.PUBLIC_URL + "/images/optimized/DSC07468.webp", title: "Engagement photo" },
    { src: process.env.PUBLIC_URL + "/images/optimized/DSC07454.webp", title: "Engagement photo" },
    { src: process.env.PUBLIC_URL + "/images/optimized/DSC07946.webp", title: "Engagement photo" },
    { src: process.env.PUBLIC_URL + "/images/optimized/image2.webp", title: "Engagement photo" },
    { src: process.env.PUBLIC_URL + "/images/optimized/DSC08193.webp", title: "Engagement photo" },
    { src: process.env.PUBLIC_URL + "/images/optimized/image1.webp", title: "Engagement photo" },
    { src: process.env.PUBLIC_URL + "/images/optimized/image3.webp", title: "" },
  ];

  return (
    <section className="gallery-section">
      <h2 className="gallery-title" data-aos="fade-down">Photo Gallery</h2>

      {loading ? (
        <div className="loader">
          <div className="heart"></div>
        </div>
      ) : (
        <div className="gallery">
          {slides.map((slide, i) => (
            <div
              key={i}
              data-aos={i % 2 === 0 ? "fade-up" : "zoom-in"}
              data-aos-delay={i * 100}
              style={{ position: "relative" }}
            >
              <img
                src={slide.src}
                alt={slide.title}
                loading="lazy"
                onClick={() => setOpen(true)}
                style={{
                  width: "100%",
                  marginBottom: "20px",
                  borderRadius: "12px",
                  cursor: "pointer",
                  transition: "transform 0.3s ease, box-shadow 0.3s ease"
                }}
              />
              <div className="caption">{slide.title}</div>
            </div>
          ))}
        </div>
      )}

      {open && (
        <Lightbox
          open={open}
          close={() => setOpen(false)}
          slides={slides}
          plugins={[Thumbnails, Zoom]}
        />
      )}
    </section>
  );
}

export default Gallery;
